/// Resolve a General_Category value name to its sorted ranges, or null
/// if `name` is not a value ECMA-262 §22.2.1.1 recognises. Exact,
/// case-sensitive match (no loose UCD matching).
pub fn generalCategory(name: []const u8) ?[]const Range {
    if (std.mem.eql(u8, name, "Lu")) return &gc_Lu;
    if (std.mem.eql(u8, name, "Uppercase_Letter")) return &gc_Lu;
    if (std.mem.eql(u8, name, "Ll")) return &gc_Ll;
    if (std.mem.eql(u8, name, "Lowercase_Letter")) return &gc_Ll;
    if (std.mem.eql(u8, name, "Lt")) return &gc_Lt;
    if (std.mem.eql(u8, name, "Titlecase_Letter")) return &gc_Lt;
    if (std.mem.eql(u8, name, "Lm")) return &gc_Lm;
    if (std.mem.eql(u8, name, "Modifier_Letter")) return &gc_Lm;
    if (std.mem.eql(u8, name, "Lo")) return &gc_Lo;
    if (std.mem.eql(u8, name, "Other_Letter")) return &gc_Lo;
    if (std.mem.eql(u8, name, "Mn")) return &gc_Mn;
    if (std.mem.eql(u8, name, "Nonspacing_Mark")) return &gc_Mn;
    if (std.mem.eql(u8, name, "Mc")) return &gc_Mc;
    if (std.mem.eql(u8, name, "Spacing_Mark")) return &gc_Mc;
    if (std.mem.eql(u8, name, "Me")) return &gc_Me;
    if (std.mem.eql(u8, name, "Enclosing_Mark")) return &gc_Me;
    if (std.mem.eql(u8, name, "Nd")) return &gc_Nd;
    if (std.mem.eql(u8, name, "Decimal_Number")) return &gc_Nd;
    if (std.mem.eql(u8, name, "digit")) return &gc_Nd;
    if (std.mem.eql(u8, name, "Nl")) return &gc_Nl;
    if (std.mem.eql(u8, name, "Letter_Number")) return &gc_Nl;
    if (std.mem.eql(u8, name, "No")) return &gc_No;
    if (std.mem.eql(u8, name, "Other_Number")) return &gc_No;
    if (std.mem.eql(u8, name, "Pc")) return &gc_Pc;
    if (std.mem.eql(u8, name, "Connector_Punctuation")) return &gc_Pc;
    if (std.mem.eql(u8, name, "Pd")) return &gc_Pd;
    if (std.mem.eql(u8, name, "Dash_Punctuation")) return &gc_Pd;
    if (std.mem.eql(u8, name, "Ps")) return &gc_Ps;
    if (std.mem.eql(u8, name, "Open_Punctuation")) return &gc_Ps;
    if (std.mem.eql(u8, name, "Pe")) return &gc_Pe;
    if (std.mem.eql(u8, name, "Close_Punctuation")) return &gc_Pe;
    if (std.mem.eql(u8, name, "Pi")) return &gc_Pi;
    if (std.mem.eql(u8, name, "Initial_Punctuation")) return &gc_Pi;
    if (std.mem.eql(u8, name, "Pf")) return &gc_Pf;
    if (std.mem.eql(u8, name, "Final_Punctuation")) return &gc_Pf;
    if (std.mem.eql(u8, name, "Po")) return &gc_Po;
    if (std.mem.eql(u8, name, "Other_Punctuation")) return &gc_Po;
    if (std.mem.eql(u8, name, "Sm")) return &gc_Sm;
    if (std.mem.eql(u8, name, "Math_Symbol")) return &gc_Sm;
    if (std.mem.eql(u8, name, "Sc")) return &gc_Sc;
    if (std.mem.eql(u8, name, "Currency_Symbol")) return &gc_Sc;
    if (std.mem.eql(u8, name, "Sk")) return &gc_Sk;
    if (std.mem.eql(u8, name, "Modifier_Symbol")) return &gc_Sk;
    if (std.mem.eql(u8, name, "So")) return &gc_So;
    if (std.mem.eql(u8, name, "Other_Symbol")) return &gc_So;
    if (std.mem.eql(u8, name, "Zs")) return &gc_Zs;
    if (std.mem.eql(u8, name, "Space_Separator")) return &gc_Zs;
    if (std.mem.eql(u8, name, "Zl")) return &gc_Zl;
    if (std.mem.eql(u8, name, "Line_Separator")) return &gc_Zl;
    if (std.mem.eql(u8, name, "Zp")) return &gc_Zp;
    if (std.mem.eql(u8, name, "Paragraph_Separator")) return &gc_Zp;
    if (std.mem.eql(u8, name, "Cc")) return &gc_Cc;
    if (std.mem.eql(u8, name, "Control")) return &gc_Cc;
    if (std.mem.eql(u8, name, "cntrl")) return &gc_Cc;
    if (std.mem.eql(u8, name, "Cf")) return &gc_Cf;
    if (std.mem.eql(u8, name, "Format")) return &gc_Cf;
    if (std.mem.eql(u8, name, "Cs")) return &gc_Cs;
    if (std.mem.eql(u8, name, "Surrogate")) return &gc_Cs;
    if (std.mem.eql(u8, name, "Co")) return &gc_Co;
    if (std.mem.eql(u8, name, "Private_Use")) return &gc_Co;
    if (std.mem.eql(u8, name, "Cn")) return &gc_Cn;
    if (std.mem.eql(u8, name, "Unassigned")) return &gc_Cn;
    if (std.mem.eql(u8, name, "L")) return &gc_L;
    if (std.mem.eql(u8, name, "Letter")) return &gc_L;
    if (std.mem.eql(u8, name, "LC")) return &gc_LC;
    if (std.mem.eql(u8, name, "Cased_Letter")) return &gc_LC;
    if (std.mem.eql(u8, name, "M")) return &gc_M;
    if (std.mem.eql(u8, name, "Mark")) return &gc_M;
    if (std.mem.eql(u8, name, "Combining_Mark")) return &gc_M;
    if (std.mem.eql(u8, name, "N")) return &gc_N;
    if (std.mem.eql(u8, name, "Number")) return &gc_N;
    if (std.mem.eql(u8, name, "P")) return &gc_P;
    if (std.mem.eql(u8, name, "Punctuation")) return &gc_P;
    if (std.mem.eql(u8, name, "punct")) return &gc_P;
    if (std.mem.eql(u8, name, "S")) return &gc_S;
    if (std.mem.eql(u8, name, "Symbol")) return &gc_S;
    if (std.mem.eql(u8, name, "Z")) return &gc_Z;
    if (std.mem.eql(u8, name, "Separator")) return &gc_Z;
    if (std.mem.eql(u8, name, "C")) return &gc_C;
    if (std.mem.eql(u8, name, "Other")) return &gc_C;
    return null;
}

/// Resolve a binary Unicode property name to its sorted ranges, or null
/// if `name` is not a binary property ECMA-262 §22.2.1.1 recognises.
pub fn binaryProperty(name: []const u8) ?[]const Range {
    if (std.mem.eql(u8, name, "ASCII")) return &bp_ASCII;
    if (std.mem.eql(u8, name, "ASCII_Hex_Digit")) return &bp_ASCII_Hex_Digit;
    if (std.mem.eql(u8, name, "AHex")) return &bp_ASCII_Hex_Digit;
    if (std.mem.eql(u8, name, "Alphabetic")) return &bp_Alphabetic;
    if (std.mem.eql(u8, name, "Alpha")) return &bp_Alphabetic;
    if (std.mem.eql(u8, name, "Any")) return &bp_Any;
    if (std.mem.eql(u8, name, "Assigned")) return &bp_Assigned;
    if (std.mem.eql(u8, name, "Bidi_Control")) return &bp_Bidi_Control;
    if (std.mem.eql(u8, name, "Bidi_C")) return &bp_Bidi_Control;
    if (std.mem.eql(u8, name, "Bidi_Mirrored")) return &bp_Bidi_Mirrored;
    if (std.mem.eql(u8, name, "Bidi_M")) return &bp_Bidi_Mirrored;
    if (std.mem.eql(u8, name, "Case_Ignorable")) return &bp_Case_Ignorable;
