    if (std.mem.eql(u8, name, "Changes_When_NFKC_Casefolded")) return &bp_Changes_When_NFKC_Casefolded;
    if (std.mem.eql(u8, name, "CWKCF")) return &bp_Changes_When_NFKC_Casefolded;
    if (std.mem.eql(u8, name, "Changes_When_Titlecased")) return &bp_Changes_When_Titlecased;
    if (std.mem.eql(u8, name, "CWT")) return &bp_Changes_When_Titlecased;
