/// A §22.2.1.1 *property of strings*: single-code-point members folded
/// into `ranges`, plus the multi-code-point `sequences`. Valid only
/// under the `/v` flag and only in positive (non-complemented) form.
pub const StringProp = struct {
    ranges: []const Range,
    sequences: []const []const u21,
};

/// Resolve a property-of-strings name to its members, or null if `name`
/// is not one of the §22.2.1.1 emoji-sequence properties. Exact match;
/// each property's short name equals its long name (UTS #51).
pub fn stringProperty(name: []const u8) ?StringProp {
    if (std.mem.eql(u8, name, "Basic_Emoji")) return .{ .ranges = &strprop_Basic_Emoji_ranges, .sequences = &strprop_Basic_Emoji_seqs };
    if (std.mem.eql(u8, name, "Emoji_Keycap_Sequence")) return .{ .ranges = &strprop_Emoji_Keycap_Sequence_ranges, .sequences = &strprop_Emoji_Keycap_Sequence_seqs };
    if (std.mem.eql(u8, name, "RGI_Emoji_Modifier_Sequence")) return .{ .ranges = &strprop_RGI_Emoji_Modifier_Sequence_ranges, .sequences = &strprop_RGI_Emoji_Modifier_Sequence_seqs };
    if (std.mem.eql(u8, name, "RGI_Emoji_Flag_Sequence")) return .{ .ranges = &strprop_RGI_Emoji_Flag_Sequence_ranges, .sequences = &strprop_RGI_Emoji_Flag_Sequence_seqs };
    if (std.mem.eql(u8, name, "RGI_Emoji_Tag_Sequence")) return .{ .ranges = &strprop_RGI_Emoji_Tag_Sequence_ranges, .sequences = &strprop_RGI_Emoji_Tag_Sequence_seqs };
    if (std.mem.eql(u8, name, "RGI_Emoji_ZWJ_Sequence")) return .{ .ranges = &strprop_RGI_Emoji_ZWJ_Sequence_ranges, .sequences = &strprop_RGI_Emoji_ZWJ_Sequence_seqs };
    if (std.mem.eql(u8, name, "RGI_Emoji")) return .{ .ranges = &strprop_RGI_Emoji_ranges, .sequences = &strprop_RGI_Emoji_seqs };
    return null;
}

